import UIKit
import WebKit

class ViewController: UIViewController {

    let webView = WKWebView()
    var jsContext: WKScriptMessageHandler?

    override func viewDidLoad() {
        super.viewDidLoad()

        // Load mobile website into WKWebView
        guard let url = URL(string: "https://your-mobile-website.com") else { return }
        webView.load(URLRequest(url: url))
        webView.scrollView.isScrollEnabled = true

        // Enable JavaScript for full web app functionality
        webView.configuration.userContentController.add(self, name: "nativeCall")

        // Add WKWebView to view controller's view
        view.addSubview(webView)
        webView.translatesAutoresizingMaskIntoConstraints = false
        NSLayoutConstraint.activate([
            webView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            webView.leadingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.leadingAnchor),
            webView.trailingAnchor.constraint(equalTo: view.safeAreaLayoutGuide.trailingAnchor),
            webView.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor)
        ])

        // Add WKWebView delegate to handle navigation
        webView.navigationDelegate = self

        // Add WKWebView configuration for camera access and push notifications
        let config = WKWebViewConfiguration()
        config.processPool = WKProcessPool()
        config.userContentController.add(self, name: "nativeCall")
        webView.configuration = config
    }

    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        switch message.name {
        case "cameraAccess":
            // Handle camera access request from web content
            print("Camera access requested")
            let alertController = UIAlertController(title: "Camera Access", message: "Do you want to allow camera access?", preferredStyle: .alert)
            alertController.addAction(UIAlertAction(title: "Allow", style: .default))
            alertController.addAction(UIAlertAction(title: "Deny", style: .destructive))
            present(alertController, animated: true)
        case "pushNotifications":
            // Handle push notifications request from web content
            print("Push notifications requested")
            let alertController = UIAlertController(title: "Push Notifications", message: "Do you want to allow push notifications?", preferredStyle: .alert)
            alertController.addAction(UIAlertAction(title: "Allow", style: .default))
            alertController.addAction(UIAlertAction(title: "Deny", style: .destructive))
            present(alertController, animated: true)
        default:
            break
        }
    }

    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        if let url = navigationAction.request.url {
            if url.absoluteString.hasPrefix("https://your-mobile-website.com") {
                decisionHandler(.allow)
            } else {
                decisionHandler(.cancel)
            }
        } else {
            decisionHandler(.cancel)
        }
    }

